def format_for_report(self) -> str:
        """Format trace as markdown for inclusion in the final report."""
        if not self.steps:
            return ""
        lines = ["## Reasoning Trace\n"]
        for step in self.steps:
            lines.append(f"### Iteration {step.iteration}")
            if step.learned:
                lines.append("**Learned:**")
                lines.extend(f"- {x}" for x in step.learned)
            if step.contradictions:
                lines.append("**Contradictions:**")
                lines.extend(f"- ⚠️ {x}" for x in step.contradictions)
            if step.refutations:
                lines.append("**Refutations (Phase Inversion):**")
                lines.extend(f"- 🔄 {x}" for x in step.refutations)
            if step.gaps:
                lines.append("**Open questions:**")
                lines.extend(f"- ❓ {x}" for x in step.gaps)
            lines.append(
                f"**Confidence:** {step.confidence:.0%} | "
                f"**Info gain:** {step.info_gain:.3f} | "
                f"**New results:** {step.new_results}"
            )
            lines.append("")
        return "\n".join(lines)

def _dismiss_notification(notif_id: str) -> bool:
    """Set notification as dismissed. Rewrites JSONL."""
    notif_file = MNEME / "notifications.jsonl"
    if not notif_file.exists():
        return False
    lines = notif_file.read_text("utf-8").strip().split("\n")
    found = False
    new_lines = []
    for line in lines:
        if not line.strip():
            continue
        try:
            rec = json.loads(line)
            if rec.get("id") == notif_id:
                rec["dismissed"] = True
                rec["dismissed_at"] = datetime.now(timezone.utc).isoformat()
                found = True
            new_lines.append(json.dumps(rec, ensure_ascii=False))
        except Exception:
            new_lines.append(line)
    if found:
        notif_file.write_text("\n".join(new_lines) + "\n", "utf-8")
    return found

