def _generate_a2_rationale(derivative: str, scores: Dict[str, int]) -> str:
    """Generate rationale for A2 derivative selection."""
    rationales = {
        "affi": f"スコア {scores['affi']} — 肯定判定（Affirm：コミットメント）が検出",
        "nega": f"スコア {scores['nega']} — 否定判定（Negate：拒否）が検出",
