def _pearson_r(xs: list[float], ys: list[float]) -> float:
    n = len(xs)
    if n < 2:
        return 0.0
    mx, my = _mean(xs), _mean(ys)
    cov = sum((x - mx) * (y - my) for x, y in zip(xs, ys)) / n
    sx, sy = _std(xs), _std(ys)
    if sx < 1e-12 or sy < 1e-12:
        return 0.0
    return cov / (sx * sy)

