def extract_implicit_coordinates(node: Any) -> Set[str]:
    """AST を再帰走査し、全 Workflow ノードの wf_id から暗黙座標を収集する。

    各動詞は Flow × 修飾座標 の直積なので、座標修飾子なしでも
    「どの座標を暗黙的にカバーするか」が VERB_IMPLICIT_COORDINATES で決定される。

    Returns:
        暗黙的にカバーされる座標の集合 (e.g., {"Va", "Fu", "Pr"})
    """
    coords: Set[str] = set()

    if node is None:
        return coords

    # --- Workflow ノード: wf_id から暗黙座標を解決 ---
    if isinstance(node, Workflow):
        implicit = VERB_IMPLICIT_COORDINATES.get(node.id, frozenset())
        coords |= implicit
        return coords

    # --- PartialDiff: body 内の暗黙座標も収集 ---
    if isinstance(node, PartialDiff):
        coords |= extract_implicit_coordinates(node.body)
        return coords

    # --- ModifierPeras: base_wf 内の暗黙座標も収集 ---
    if isinstance(node, ModifierPeras):
        coords |= extract_implicit_coordinates(node.base_wf)
        return coords

    # --- 二項ノード ---
    if isinstance(node, (Fusion, Oscillation)):
        coords |= extract_implicit_coordinates(node.left)
        coords |= extract_implicit_coordinates(node.right)
        return coords

    if isinstance(node, Morphism):
        coords |= extract_implicit_coordinates(node.source)
        coords |= extract_implicit_coordinates(node.target)
        return coords

    if isinstance(node, Adjunction):
        coords |= extract_implicit_coordinates(node.left)
        coords |= extract_implicit_coordinates(node.right)
        return coords

    # --- リストノード ---
    if isinstance(node, Sequence):
        for step in node.steps:
            coords |= extract_implicit_coordinates(step)
        return coords

    if isinstance(node, Pipeline):
        for step in node.steps:
            coords |= extract_implicit_coordinates(step)
        return coords

    if isinstance(node, Parallel):
        for branch in node.branches:
            coords |= extract_implicit_coordinates(branch)
        return coords

    # --- 制御構文 ---
    if isinstance(node, ConvergenceLoop):
        coords |= extract_implicit_coordinates(node.body)
        return coords

    if isinstance(node, ForLoop):
        coords |= extract_implicit_coordinates(node.body)
        return coords

    if isinstance(node, WhileLoop):
        coords |= extract_implicit_coordinates(node.body)
        return coords

    if isinstance(node, IfCondition):
        coords |= extract_implicit_coordinates(node.then_branch)
        if node.else_branch is not None:
            coords |= extract_implicit_coordinates(node.else_branch)
        return coords

    if isinstance(node, Lambda):
        coords |= extract_implicit_coordinates(node.body)
        return coords

    if isinstance(node, TaggedBlock):
        coords |= extract_implicit_coordinates(node.body)
        return coords

    if isinstance(node, Group):
        coords |= extract_implicit_coordinates(node.body)
        return coords

    if isinstance(node, ColimitExpansion):
        coords |= extract_implicit_coordinates(node.body)
        return coords

    if isinstance(node, Integral):
        coords |= extract_implicit_coordinates(node.body)
        return coords

    if isinstance(node, Summation):
        if node.body is not None:
            coords |= extract_implicit_coordinates(node.body)
        return coords

    if isinstance(node, LetBinding):
        coords |= extract_implicit_coordinates(node.body)
        return coords

    if isinstance(node, Program):
        for expr in node.expressions:
            coords |= extract_implicit_coordinates(expr)
        return coords

    return coords

def _parse_for(self, expr: str) -> ForLoop:
        """FOR ループをパース: F:[×N]{body} or F:[A,B]{body} or F:N{body}"""
        # Pattern 1: F:[...]{body} (角括弧あり、ネスト対応)
        bracket_match = re.match(r'F:\[([^\]]+)\]', expr)
        if bracket_match:
            iter_spec = bracket_match.group(1).strip()
            rest_after_bracket = expr[bracket_match.end():]
            body_str, rest = self._extract_braced_body(rest_after_bracket)
            if body_str is not None:
                # ×N 形式
                if iter_spec.startswith('×'):
                    iterations = int(iter_spec[1:])
                else:
                    # リスト形式
                    iterations = [i.strip() for i in iter_spec.split(',')]

                body = self._parse_expression(body_str)

                # body 後に続く式がある場合 (例: F:[...]{...}, ~(...))
                if rest:
                    for_node = ForLoop(iterations=iterations, body=body)
                    if rest.startswith(','):
                        rest = rest[1:].strip()
                    if rest.startswith('_'):
                        rest = rest[1:].strip()
                    if rest:
                        rest_node = self._parse_expression(rest)
                        return Sequence(steps=[for_node, rest_node])
                    return for_node

                return ForLoop(iterations=iterations, body=body)

        # Pattern 2: F:N{body} (角括弧なし、数値直接指定)
        num_match = re.match(r'F:(\d+)', expr)
        if num_match:
            iterations = int(num_match.group(1))
            rest_after_num = expr[num_match.end():]
            body_str, _ = self._extract_braced_body(rest_after_num)
            if body_str is not None:
                body = self._parse_expression(body_str)
                return ForLoop(iterations=iterations, body=body)

        raise ValueError(f"Invalid FOR loop: {expr}")

