def _load_wf_descriptions(wf_ids: list[str]) -> list[str]:
    """WF ID 群の description を frontmatter から読み取る。"""
    descriptions = []
    for wf_id in wf_ids:
        wf_path = _WF_DIR / f"{wf_id}.md"
        if not wf_path.exists():
            continue
        try:
            text = wf_path.read_text(encoding="utf-8")
            # YAML frontmatter の description を抽出 (簡易パーサー)
            if text.startswith("---"):
                end = text.find("---", 3)
                if end > 0:
                    front = text[3:end]
                    for line in front.splitlines():
                        if line.startswith("description:"):
                            desc = line[len("description:"):].strip().strip('"').strip("'")
                            if desc:
                                descriptions.append(desc)
                            break
        except OSError:
            continue
    return descriptions

