def _parse_limit_output(self, text: str) -> LimitResult:
        """Parse structured Limit output (or C3 final output) into LimitResult"""
        result = LimitResult()

        for line in text.split("\n"):
            line = line.strip()
            # Support both plain labels and Markdown bold format
            clean = line.lstrip("- *").rstrip("*")
            if clean.startswith("C0_PW:") or clean.startswith("C0 PW:"):
                result.c0_pw = clean.split(":", 1)[1].strip()
            elif clean.startswith("C1_CONTRAST:") or clean.startswith("C1 対比:"):
                result.c1_contrast = clean.split(":", 1)[1].strip()
            elif clean.startswith("C2_FUSION:") or clean.startswith("C2 融合:"):
                result.c2_fusion = clean.split(":", 1)[1].strip()
            elif clean.startswith("C3_KALON:") or clean.startswith("C3 Kalon:") or clean.startswith("KALON:"):
                result.c3_kalon = clean.split(":", 1)[1].strip()
            elif clean.startswith("CONCLUSION:"):
                result.conclusion = clean[len("CONCLUSION:"):].strip()
            elif clean.startswith("CONFIDENCE:"):
                try:
                    result.confidence = float(
                        clean[len("CONFIDENCE:"):].strip().rstrip("%")
                    ) / 100.0
                except ValueError:
                    result.confidence = 0.5
            elif clean.startswith("COORDINATE:"):
                result.coordinate_value = clean[len("COORDINATE:"):].strip()

        # If structured parsing failed, use full text as conclusion
        if not result.conclusion and text:
            result.conclusion = text[:200]
            result.confidence = 0.5

        return result

pairs.func_b_source:
def _compose_forget_levels(node: Any, fmap: Dict[str, int]) -> int:
        """AST 構造に基づく忘却レベルの合成。"""
        from hermeneus.src.ccl_ast import (
            Workflow as WfNode, Oscillation as Osc, Fusion as Fus,
            Sequence as Seq, Pipeline as Pipe, Parallel as Par,
            ForLoop as FLp, IfCondition as IfC, ColimitExpansion as Col, Group
        )
        if isinstance(node, WfNode):
            return fmap.get(f"/{node.id}", 2)
        elif isinstance(node, Osc):
            l = _compose_forget_levels(node.left, fmap)
            r = _compose_forget_levels(node.right, fmap)
            if getattr(node, 'divergent', False):
                # ~! 発散振動: max — 情報が散乱する
                return max(l, r)
            else:
                # ~ / ~* 収束振動: min — 反復は情報を回復する
                return min(l, r)
        elif isinstance(node, Fus):
            # Fusion: max — 融合は保守的
            l = _compose_forget_levels(node.left, fmap)
            r = _compose_forget_levels(node.right, fmap)
            return max(l, r)
        elif isinstance(node, (Seq, Pipe)):
            # Sequence/Pipeline: max — 順次は情報が減衰する
            children = getattr(node, 'steps', [])
            if not children:
                return 2
            return max(_compose_forget_levels(c, fmap) for c in children)
        elif isinstance(node, Par):
            # Parallel: min — 並列は最も保存する分岐が活きる
            branches = getattr(node, 'branches', [])
            if not branches:
                return 2
            return min(_compose_forget_levels(c, fmap) for c in branches)
        elif isinstance(node, (FLp, IfC)):
            body = getattr(node, 'body', None)
            if body:
                return _compose_forget_levels(body, fmap)
            return 2
        elif isinstance(node, Col):
            return _compose_forget_levels(node.body, fmap)
        elif isinstance(node, Group):
            return _compose_forget_levels(node.body, fmap)
        return 2

