def from_dataclass(cls, dataclass_type: Type) -> Dict[str, Any]:
        """dataclass から JSON Schema を生成"""
        hints = get_type_hints(dataclass_type)

        properties = {}
        required = []

        for field_name, field_type in hints.items():
            # Optional 型の処理
            is_optional = False
            origin = getattr(field_type, "__origin__", None)

            if origin is Union:
                args = field_type.__args__
                if type(None) in args:
                    is_optional = True
                    # None 以外の型を取得
                    field_type = [a for a in args if a is not type(None)][0]

            # 型変換
            schema = cls._type_to_schema(field_type)
            properties[field_name] = schema

            if not is_optional:
                required.append(field_name)

        return {
            "type": "object",
            "properties": properties,
            "required": required,
            "additionalProperties": False
        }

pairs.func_b_source:
def _default_metric(self, example, prediction, trace=None) -> float:
        """デフォルトメトリクス: 出力の類似度"""
        expected = getattr(example, 'output', '')
        predicted = getattr(prediction, 'output', '')

        if not expected or not predicted:
            return 0.0

        # 簡易類似度 (完全一致 or 部分一致)
        if expected.lower() == predicted.lower():
            return 1.0
        elif expected.lower() in predicted.lower():
            return 0.8
        elif predicted.lower() in expected.lower():
            return 0.6
        else:
            # 単語オーバーラップ
            expected_words = set(expected.lower().split())
            predicted_words = set(predicted.lower().split())
            overlap = len(expected_words & predicted_words)
            total = len(expected_words | predicted_words)
            return overlap / total if total > 0 else 0.0

pairs.func_a_source:
def _parse_lambda(self, expr: str) -> Lambda:
        """Lambda をパース: L:[x]{body}"""
        match = re.match(r'L:\[([^\]]+)\]\{(.+)\}$', expr)
        if not match:
            raise ValueError(f"Invalid Lambda: {expr}")

        params = [p.strip() for p in match.group(1).split(',')]
        body = self._parse_expression(match.group(2))

        return Lambda(params=params, body=body)

