async def emit_async(self, event: Any) -> List[Optional[str]]:
        """イベントを非同期に全 subscriber に配信"""
        if not self.enabled:
            return []

        self._stats["total_emits"] += 1

        async def _run_sub(sub: Any) -> Optional[str]:
            sub_name = getattr(sub, 'name', sub.__class__.__name__)
            try:
                if hasattr(sub, 'should_activate'):
                    if not sub.should_activate(event):
                        return None

                self._stats["total_activations"] += 1

                if hasattr(sub, 'handle_async'):
                    return await sub.handle_async(event)
                else:
                    return sub.handle(event)

            except Exception as e:
                self._stats["total_errors"] += 1
                self._errors.append(EnvironmentError(
                    subscriber_name=sub_name,
                    error=e,
                ))
                logger.warning("Environment async error in %s: %s", sub_name, e)
                return None

        results = await asyncio.gather(
            *[_run_sub(sub) for sub in self._subscribers],
            return_exceptions=False,
        )

        for sub, output in zip(self._subscribers, results):
            if output:
                sub_name = getattr(sub, 'name', sub.__class__.__name__)
                self._outputs.append({
                    "subscriber": sub_name,
                    "output": str(output),
                    "event_type": getattr(
                        getattr(event, 'event_type', None), 'value', 'unknown'
                    ),
                })

        return list(results)

def get_macro_metadata() -> Dict[str, dict]:
    """
    nous/workflows/*.md から YAML フロントマターのメタデータを抽出

    ccl- プレフィックス付きファイルを正規定義として優先する。
    例: ccl-vet.md と vet.md が両方存在する場合、ccl-vet.md のメタデータを使用。

    Returns:
        {"macro_name": {"version": "1.0", "min_convergence_iters": 3, ...}, ...}
    """
    import yaml
    metadata = {}

    if not WF_MACROS_DIR.exists():
        return metadata

    # ccl- プレフィックス付きファイルの名前セットを先に構築
    ccl_prefixed_names = {
        p.stem.replace("ccl-", "", 1)
        for p in WF_MACROS_DIR.glob("ccl-*.md")
    }

    for path in WF_MACROS_DIR.glob("*.md"):
        name = path.stem
        is_ccl_prefixed = name.startswith("ccl-")
        if is_ccl_prefixed:
            name = name.replace("ccl-", "", 1)
        elif name in ccl_prefixed_names:
            # ccl- 版が存在する → 非プレフィックス版はスキップ
            continue

        try:
            content = path.read_text(encoding="utf-8")
        except Exception:
            continue

        if content.startswith("---"):
            end_idx = content.find("---", 3)
            if end_idx != -1:
                fm_str = content[3:end_idx]
                try:
                    fm = yaml.safe_load(fm_str)
                    if isinstance(fm, dict):
                        metadata[name] = fm
                except yaml.YAMLError:
                    continue

    return metadata

