async def run_sync(fn, *args, timeout_sec: float = 120.0, **kwargs):
    """Run sync function in thread pool. See mekhane.mcp.mcp_base.run_sync."""
    label = getattr(fn, '__qualname__', None) or getattr(fn, '__name__', repr(fn))
    coro = asyncio.to_thread(fn, *args, **kwargs)
    if timeout_sec > 0:
        try:
            return await asyncio.wait_for(coro, timeout=timeout_sec)
        except asyncio.TimeoutError:
            raise TimeoutError(f"Sync call '{label}' timed out after {timeout_sec}s")
    return await coro

async def execute_async(
        self,
        lmql_code: str,
        context: str = "",
        variables: Optional[Dict[str, Any]] = None
    ) -> ExecutionResult:
        """LMQL プログラムを非同期実行"""
        variables = variables or {}

        try:
            if self._lmql_available:
                result = await self._execute_with_lmql(lmql_code, context, variables)
                # LMQL 実行失敗 → Fallback (直接 LLM API) へ
                if result.status == ExecutionStatus.ERROR:
                    return await self._execute_fallback(lmql_code, context, variables)
                return result
            else:
                return await self._execute_fallback(lmql_code, context, variables)
        except asyncio.TimeoutError:
            return ExecutionResult(
                status=ExecutionStatus.TIMEOUT,
                output="",
                error=f"Execution timed out after {self.config.timeout} seconds"
            )
        except Exception as e:
            return ExecutionResult(
                status=ExecutionStatus.ERROR,
                output="",
                error=str(e)
            )

