def generate_detail(
        self,
        limit: int = 10,
        period: str = "last_7_days"
    ) -> str:
        """詳細レポートを生成"""
        since = self._parse_period(period)
        records = self.store.query(since=since, limit=limit)

        if not records:
            return "レコードがありません。"

        lines = ["# 監査詳細レポート\n"]

        for i, rec in enumerate(records, 1):
            status = "✅ ACCEPT" if rec.consensus_accepted else "❌ REJECT"
            lines.append(f"""
## {i}. {rec.record_id}

- **CCL**: `{rec.ccl_expression}`
- **判定**: {status}
- **確信度**: {rec.confidence:.2%}
- **時刻**: {rec.timestamp.strftime('%Y-%m-%d %H:%M')}
""")
            if rec.dissent_reasons:
                lines.append("- **反対意見**:")
                for reason in rec.dissent_reasons:
                    lines.append(f"  - {reason}")

        return "\n".join(lines)

pairs.func_b_source:
def _extract_structured_meta(output: str) -> tuple[str, Dict[str, Any]]:
    """LLM 出力末尾の JSON ブロックを抽出する。

    Returns:
        (clean_output, meta_dict) — JSON が見つからない場合は空 dict。
    """
    import json as _json
    import re as _re

    # ```json ... ``` ブロックを探す (複数ある場合は最後のもの)
    pattern = _re.compile(r'```json\s*\n(\{.*?\})\s*\n```', _re.DOTALL)
    matches = list(pattern.finditer(output))
    if not matches:
        return output, {}

    last_match = matches[-1]
    try:
        meta = _json.loads(last_match.group(1))
        if not isinstance(meta, dict):
            return output, {}

        # jsonschema による検証 (Phase 1 導入)
        try:
            from jsonschema import validate, ValidationError
            from hermeneus.src.schemas import WF_META_SCHEMA
            validate(instance=meta, schema=WF_META_SCHEMA)
        except ImportError:
            pass  # jsonschema がない場合はスキップ
        except Exception as e:
            logger.warning(f"structured_meta schema validation failed: {e}")
            # 無効なフィールドをフィルタするか、最低限 format を保つか
            # ここでは厳格にせず、取得できたものを返す (フェーズ1)

        # JSON ブロックを出力から除去 (表示をクリーンにする)
        clean = output[:last_match.start()].rstrip()
        return clean, meta
    except (_json.JSONDecodeError, ValueError):
        return output, {}

def compute(self, code_to_output: Dict[str, str]) -> Dict[tuple, float]:
        """6 Peras 出力間の新規性 (テキスト距離) から張力 (0.0-1.0) を算出"""
        if not code_to_output or len(code_to_output) < 2:
            return {}

        codes = list(code_to_output.keys())
        texts = [code_to_output[c] for c in codes]

        # 1. Vertex AI (API, no CPU overhead)
        try:
            from mekhane.anamnesis.vertex_embedder import VertexEmbedder
            from mekhane.anamnesis.constants import EMBED_MODEL
            embedder = VertexEmbedder(model_name=EMBED_MODEL, dimension=3072)
            all_novelties = embedder.pairwise_novelty(
                [t[:2000] for t in texts], labels=codes,
            )
            scores = {}
            for edge_def in X_SERIES_EDGES:
                a, b = edge_def["edge"]
                tension = all_novelties.get((a, b), all_novelties.get((b, a), 0.0))
                scores[(a, b)] = tension
            return scores
        except Exception:
            pass

        # 2. BGE-M3 (local CPU fallback)
        try:
            from mekhane.anamnesis.index import Embedder
            embedder = Embedder()
            all_novelties = embedder.pairwise_novelty(
                [t[:2000] for t in texts], labels=codes,
            )
            scores = {}
            for edge_def in X_SERIES_EDGES:
                a, b = edge_def["edge"]
                tension = all_novelties.get((a, b), all_novelties.get((b, a), 0.0))
                scores[(a, b)] = tension
            return scores
        except (ImportError, RuntimeError):
            pass

        # 3. TF-IDF (stdlib only, last resort)
        return self._compute_tfidf(codes, texts)

